// SOURCE OF TRUTH: supabase/functions/resume-strengthen/strength.ts — keep in sync
// Verbatim JS copies of getLineAtTarget + selectIssues (TypeScript types stripped).

const WEAK_BASELINE = 40;
const CAP_NORMAL = 5;
const CAP_WEAK = 7;

// Runtime guard: numeric-string indices ('0' instead of 0) are a common slip
// in this Code-node copy. Only genuine integers may address a line.
const isIndex = (n) => typeof n === 'number' && Number.isInteger(n);

function getLineAtTarget(resume, t) {
  try {
    if (t.section === 'summary') return typeof resume.summary === 'string' ? resume.summary : null;
    if (t.section === 'experience') {
      if (!isIndex(t.exp_index) || !isIndex(t.bullet_index)) return null;
      return resume.experience?.[t.exp_index]?.bullets?.[t.bullet_index] ?? null;
    }
    if (t.section === 'highlights') {
      if (!isIndex(t.index)) return null;
      return resume.highlights?.[t.index] ?? null;
    }
    if (t.section === 'skills') {
      if (!isIndex(t.index)) return null;
      return resume.skills_grouped?.[t.group]?.[t.index] ?? null;
    }
    return null;
  } catch {
    return null;
  }
}

function selectIssues(baseline, candidates, resume) {
  const valid = candidates.filter((c) => getLineAtTarget(resume, c.target) !== null);
  const cap = baseline < WEAK_BASELINE ? CAP_WEAK : CAP_NORMAL;
  const surfaced = [...valid].sort((a, b) => b.impact - a.impact).slice(0, cap)
    .map((c) => ({
      ...c,
      // Sanitize LLM-authored impacts at intake: integers 1..10 only.
      impact: Math.max(1, Math.min(10, Math.round(Number(c.impact) || 1))),
      status: 'pending',
      user_input: null,
    }));
  const potential = Math.min(100, baseline + surfaced.reduce((s, i) => s + i.impact, 0));
  return {
    status: 'ready',
    score: baseline,
    score_base: baseline,
    score_potential: potential,
    language: 'en', // caller overwrites with the user's preferred_language
    generated_at: new Date().toISOString(),
    issues: surfaced,
  };
}

// ---- WF10 glue: parse the LLM output, build the review, hand off to Supabase ----
const body = $('Webhook').first().json.body;

// jsonb columns round-trip as STRING primitives when written via
// JSON.stringify into Supabase nodes (house pattern) — normalize before use.
const _norm = (v) => typeof v === 'string' ? JSON.parse(v) : v;
const resumeJson = _norm(body.resume_json);

let review;
try {
  let raw = $input.first().json.text || '';
  raw = String(raw).trim();
  if (raw.startsWith('```')) {
    raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) throw new Error('LLM did not return parseable JSON');
    parsed = JSON.parse(match[0]);
  }

  const baselineNum = Number(parsed.baseline_score);
  if (!Number.isFinite(baselineNum)) throw new Error('LLM output missing baseline_score');
  const baseline = Math.max(0, Math.min(100, Math.round(baselineNum)));

  // Never trust LLM-authored ids: assign our own iss_1..n before selection.
  const candidates = (Array.isArray(parsed.candidates) ? parsed.candidates : [])
    .filter((c) => c && typeof c === 'object');
  candidates.forEach((c, i) => { c.id = 'iss_' + (i + 1); });

  // Zero candidates is a valid outcome: the review lands 'ready' with no
  // issues and score = score_potential = baseline (the frontend renders
  // that as recruiter-ready).
  review = selectIssues(baseline, candidates, resumeJson);
  review.language = body.preferred_language || 'en';
} catch (e) {
  review = { status: 'failed', error: 'Analysis failed.' };
}

return [{ json: { custom_resume_id: body.custom_resume_id, strength_review: review } }];

