// is plain JSON (a jsonb column), so a JSON round-trip clone is behaviourally
// identical here.
const structuredClone = globalThis.structuredClone || ((o) => JSON.parse(JSON.stringify(o)));

// Runtime guard: numeric-string indices ('0' instead of 0) are a common slip
// in this Code-node copy. Only genuine integers may address a line.
const isIndex = (n) => typeof n === 'number' && Number.isInteger(n);

function getLineAtTarget(resume, t) {
  try {
    if (t.section === 'summary') return typeof resume.summary === 'string' ? resume.summary : null;
    if (t.section === 'experience') {
      if (!isIndex(t.exp_index) || !isIndex(t.bullet_index)) return null;
      return resume.experience?.[t.exp_index]?.bullets?.[t.bullet_index] ?? null;
    }
    if (t.section === 'highlights') {
      if (!isIndex(t.index)) return null;
      return resume.highlights?.[t.index] ?? null;
    }
    if (t.section === 'skills') {
      if (!isIndex(t.index)) return null;
      return resume.skills_grouped?.[t.group]?.[t.index] ?? null;
    }
    return null;
  } catch {
    return null;
  }
}

// Precondition: caller must have confirmed getLineAtTarget(resume, t) !== null.
// Throws on unresolvable targets by design — do not call blind.
function setLineAtTarget(resume, t, text) {
  const next = structuredClone(resume);
  if (t.section === 'summary') next.summary = text;
  else if (t.section === 'experience') next.experience[t.exp_index].bullets[t.bullet_index] = text;
  else if (t.section === 'highlights') next.highlights[t.index] = text;
  else if (t.section === 'skills') next.skills_grouped[t.group][t.index] = text;
  return next;
}

function computeScore(review) {
  const applied = review.issues
    .filter((i) => i.status === 'applied')
    .reduce((s, i) => s + i.impact, 0);
  return Math.min(review.score_potential, review.score_base + applied);
}

// ---- WF10 glue: patch composed lines into the résumé, finalize the review ----
const body = $('Webhook').first().json.body;

// jsonb columns round-trip as STRING primitives when written via
// JSON.stringify into Supabase nodes (house pattern) — normalize before use.
const _norm = (v) => typeof v === 'string' ? JSON.parse(v) : v;

// The edge function staged the review as 'applying' (with the user's one-tap
// progress already persisted) before firing this webhook. Input here is the
// freshly fetched custom_resumes row.
const row = $input.first().json;
const fetchedReview = _norm(row && row.strength_review);
const review = (fetchedReview && Array.isArray(fetchedReview.issues))
  ? fetchedReview
  : null;
if (!review) throw new Error('No strength_review found on custom_resumes ' + body.custom_resume_id);

// Parse the LLM output: [{id, line}]. Unparseable output means zero composed
// lines, which falls through to the partial-failure handling below.
let composed = [];
try {
  let raw = $('Compose LLM').first().json.text || '';
  raw = String(raw).trim();
  if (raw.startsWith('```')) {
    raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    const m = raw.match(/\[[\s\S]*\]/);
    parsed = m ? JSON.parse(m[0]) : [];
  }
  if (Array.isArray(parsed)) composed = parsed;
} catch (e) {
  composed = [];
}

// Only ids we actually sent may touch the résumé; drop everything else.
const sentItems = Array.isArray(body.items) ? body.items : [];
const itemsById = new Map(sentItems.map((it) => [it.id, it]));

let resume = _norm(body.resume_json);
const appliedIds = [];

for (const entry of composed) {
  if (!entry || typeof entry !== 'object') continue;
  const item = itemsById.get(entry.id);
  if (!item) continue; // unknown id: the LLM can never touch a line it wasn't sent
  if (appliedIds.indexOf(entry.id) !== -1) continue; // ignore duplicate ids
  const line = typeof entry.line === 'string' ? entry.line.trim() : '';
  if (!line) continue; // null / unusable answer: leave the issue pending
  if (getLineAtTarget(resume, item.target) === null) continue; // setLineAtTarget precondition
  resume = setLineAtTarget(resume, item.target, line);
  appliedIds.push(entry.id);
}

const nextIssues = review.issues.map((i) =>
  appliedIds.indexOf(i.id) !== -1 ? { ...i, status: 'applied' } : { ...i }
);
const nextReview = { ...review, issues: nextIssues, status: 'ready' };

const allComposed = sentItems.length > 0 && sentItems.every((it) => appliedIds.indexOf(it.id) !== -1);

if (allComposed) {
  const fullScore = Number(body.final_score);
  nextReview.score = Number.isFinite(fullScore) ? fullScore : computeScore(nextReview);
  // A fully successful compose clears any lingering self-heal error message.
  delete nextReview.error;
} else {
  nextReview.error = 'Some changes need another try.';
  nextReview.score = computeScore(nextReview);
}

return [{ json: {
  custom_resume_id: body.custom_resume_id,
  resume_json: resume,
  strength_review: nextReview,
} }];

// Compose LLM call failed. The user's one-tap progress was already persisted
// by the edge function before this webhook fired, so nothing is lost: put the
// review back to 'ready' with a retry hint, keeping issues exactly as they are.
const body = $('Webhook').first().json.body;

// Input is the freshly fetched custom_resumes row (failed-path fetch).
// jsonb columns round-trip as STRING primitives (house pattern) — normalize.
const _norm = (v) => typeof v === 'string' ? JSON.parse(v) : v;
const row = $input.first().json;
const fetchedReview = _norm(row && row.strength_review);
const review = (fetchedReview && typeof fetchedReview === 'object')
  ? fetchedReview
  : { issues: [] };

const nextReview = { ...review, status: 'ready', error: 'Some changes need another try.' };

return [{ json: { custom_resume_id: body.custom_resume_id, strength_review: nextReview } }];

